)

// usageRow holds aggregated stats for a single harness.
type usageRow struct {
	Harness                string  `json:"harness" yaml:"harness"`
	Sessions               int     `json:"sessions" yaml:"sessions"`
	InputTokens            int     `json:"input_tokens" yaml:"input_tokens"`
	OutputTokens           int     `json:"output_tokens" yaml:"output_tokens"`
	CostUSD                float64 `json:"cost_usd" yaml:"cost_usd"`
	CostBasis              string  `json:"cost_basis,omitempty" yaml:"cost_basis,omitempty"`
	AvgDurationMS          float64 `json:"avg_duration_ms" yaml:"avg_duration_ms"`
	QuotaState             string  `json:"quota_state,omitempty" yaml:"quota_state,omitempty"`
	SignalProvider         string  `json:"signal_provider,omitempty" yaml:"signal_provider,omitempty"`
	SignalKind             string  `json:"signal_kind,omitempty" yaml:"signal_kind,omitempty"`
	SignalFreshness        string  `json:"signal_freshness,omitempty" yaml:"signal_freshness,omitempty"`
	SignalBasis            string  `json:"signal_basis,omitempty" yaml:"signal_basis,omitempty"`
	NativeInputTokens      int     `json:"native_input_tokens,omitempty" yaml:"native_input_tokens,omitempty"`
	NativeOutputTokens     int     `json:"native_output_tokens,omitempty" yaml:"native_output_tokens,omitempty"`
	NativeTotalTokens      int     `json:"native_total_tokens,omitempty" yaml:"native_total_tokens,omitempty"`
	NativeSessionCount     int     `json:"native_session_count,omitempty" yaml:"native_session_count,omitempty"`
	NativeQuotaUsedPercent int     `json:"native_quota_used_percent,omitempty" yaml:"native_quota_used_percent,omitempty"`
}

type usageAgg struct {
	sessions     int
	inputTokens  int
	outputTokens int
	costUSD      float64
	totalDurMS   int
	costBasis    string
}

type usageSessionRecord struct {
	entry agent.SessionEntry
	key   string
}

func (a *usageAgg) addSession(entry agent.SessionEntry) {
	a.sessions++
	a.inputTokens += entry.InputTokens
	a.outputTokens += entry.OutputTokens
	a.totalDurMS += entry.Duration

	// Use recorded cost if available, else estimate from pricing table.
	if entry.CostUSD > 0 {
		a.costUSD += entry.CostUSD
		a.mergeCostBasis(usageCostBasisReported)
		return
	}
	if entry.Model == "" {
		return
	}
	if est := agent.EstimateCost(entry.Model, entry.InputTokens, entry.OutputTokens); est >= 0 {
		a.costUSD += est
		if est > 0 {
			a.mergeCostBasis(usageCostBasisEstimated)
		}
	}
}

// localHarnesses tracks which harness names are local-only (no provider cost).
// Replaces the previous in-package harness lookup so this file depends on
// service contract metadata instead of DDx-owned harness config.
var localHarnesses = map[string]bool{
	"agent":   true,
	"virtual": true,
	"script":  true,
}

func (a *usageAgg) addOutcome(outcome agent.RoutingOutcome) {
	a.sessions++
	a.inputTokens += outcome.InputTokens
	a.outputTokens += outcome.OutputTokens
	a.totalDurMS += outcome.LatencyMS
	if outcome.CostUSD > 0 {
		a.costUSD += outcome.CostUSD
		a.mergeCostBasis(usageCostBasisReported)
		return
	}
	if !localHarnesses[outcome.Harness] && outcome.Model != "" {
		if est := agent.EstimateCost(outcome.Model, outcome.InputTokens, outcome.OutputTokens); est >= 0 {
			a.costUSD += est
			if est > 0 {
				a.mergeCostBasis(usageCostBasisEstimated)
			}
		}
	}
}

func (a *usageAgg) toRow(harness string) usageRow {
	var avgDur float64
	if a.sessions > 0 {
		avgDur = float64(a.totalDurMS) / float64(a.sessions)
	}
	return usageRow{
		Harness:       harness,
		Sessions:      a.sessions,
		InputTokens:   a.inputTokens,
		OutputTokens:  a.outputTokens,
		CostUSD:       a.costUSD,
		CostBasis:     inferredUsageCostBasis(harness, a.costUSD, a.costBasis),
		AvgDurationMS: avgDur,
	}
}

const (
	usageCostBasisReported       = "reported"
	usageCostBasisEstimated      = "estimated"
	usageCostBasisEstimatedValue = "estimated_value"
	usageCostBasisMixed          = "mixed"
)

func (a *usageAgg) mergeCostBasis(basis string) {
	if basis == "" {
		return
	}
	if a.costBasis == "" {
		a.costBasis = basis
		return
	}
	if a.costBasis != basis {
		a.costBasis = usageCostBasisMixed
	}
}

func inferredUsageCostBasis(harness string, costUSD float64, basis string) string {
	if costUSD <= 0 {
		return ""
	}
	if isSubscriptionHarnessName(harness) {
		return usageCostBasisEstimatedValue
	}
	if basis != "" {
		return basis
	}
	return usageCostBasisEstimated
}

func isSubscriptionHarnessName(harness string) bool {
	switch strings.ToLower(harness) {
	case "claude", "codex":
		return true
	default:
		return false
	}
}

func applyUsageCostBasis(row *usageRow, isSubscription bool) {
	if row == nil || row.CostUSD <= 0 {
		return
	}
	if isSubscription {
		row.CostBasis = usageCostBasisEstimatedValue
		return
	}
	if row.CostBasis == "" {
		row.CostBasis = usageCostBasisEstimated
	}
}

func (f *CommandFactory) newAgentUsageCommand() *cobra.Command {
	cmd := &cobra.Command{
		Use:   "usage",
		Short: "Show per-harness token and cost summary",
		Args:  cobra.NoArgs,
		RunE: func(cmd *cobra.Command, args []string) error {
			harness, _ := cmd.Flags().GetString("harness")
			since, _ := cmd.Flags().GetString("since")
			format, _ := cmd.Flags().GetString("format")

			sinceTime, err := parseSince(since)
			if err != nil {
				return fmt.Errorf("invalid --since value: %w", err)
			}

			logDir := agent.SessionLogDirForWorkDir(f.WorkingDir)
			rows, err := aggregateUsageFromRoutingMetrics(logDir, harness, sinceTime)
			if err != nil {
				return err
			}
			if len(rows) == 0 {
				rows, err = aggregateUsageFromSessionIndex(logDir, harness, sinceTime, nil)
			}
			if err != nil {
				return err
			}
			rows = enrichUsageRowsWithRoutingSignals(f.WorkingDir, rows)

			switch format {
			case "json":
				return renderUsageJSON(cmd, rows)
			case "csv":
				return renderUsageCSV(cmd, rows)
			default:
				return renderUsageTable(cmd, rows)
			}
		},
	}

	cmd.Flags().String("harness", "", "Filter by harness name")
	cmd.Flags().String("since", "30d", "Time window: today, 7d, 30d, or ISO date (e.g. 2026-04-01)")
	cmd.Flags().String("format", "table", "Output format: table, json, csv")
	return cmd
}

// parseSince converts a --since string to a time.Time cutoff.
func parseSince(s string) (time.Time, error) {
	switch s {
	case "today":
		now := time.Now()
		return time.Date(now.Year(), now.Month(), now.Day(), 0, 0, 0, 0, now.Location()), nil
	case "":
		return time.Now().AddDate(0, 0, -30), nil
	}
	if strings.HasSuffix(s, "d") {
		n, err := strconv.Atoi(strings.TrimSuffix(s, "d"))
		if err != nil {
			return time.Time{}, fmt.Errorf("expected Nd format, got %q", s)
		}
		return time.Now().AddDate(0, 0, -n), nil
	}
	// Try ISO date
	t, err := time.Parse("2006-01-02", s)
	if err != nil {
		return time.Time{}, fmt.Errorf("unrecognized format %q, want today, Nd, or YYYY-MM-DD", s)

package cmd

import (
	"context"
	"encoding/json"
	"fmt"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	agentlib "github.com/DocumentDrivenDX/fizeau"
	"github.com/spf13/cobra"
)

// routeStatusJSON is the top-level JSON output shape.
type routeStatusJSON struct {
	Selection       *routeStatusSelectionJSON `json:"selection,omitempty"`
	Providers       []routeStatusProviderJSON `json:"providers,omitempty"`
	Models          []routeStatusModelJSON    `json:"models,omitempty"`
	RecentDecisions []routeStatusDecisionJSON `json:"recent_decisions,omitempty"`
	ActiveCooldowns []routeStatusCooldownJSON `json:"active_cooldowns,omitempty"`
}

type routeStatusSelectionJSON struct {
	Harness  string `json:"harness,omitempty"`
	Provider string `json:"provider,omitempty"`
	Endpoint string `json:"endpoint,omitempty"`
	Model    string `json:"model,omitempty"`
	Power    int    `json:"power,omitempty"`
	Reason   string `json:"reason,omitempty"`
}

type routeStatusProviderJSON struct {
	Name          string `json:"name"`
	Type          string `json:"type,omitempty"`
	Status        string `json:"status,omitempty"`
	DefaultModel  string `json:"default_model,omitempty"`
	CostClass     string `json:"cost_class,omitempty"`
	Quota         string `json:"quota,omitempty"`
	Usage         string `json:"usage,omitempty"`
	CooldownUntil string `json:"cooldown_until,omitempty"`
	Error         string `json:"error,omitempty"`
}

type routeStatusModelJSON struct {
	Provider             string  `json:"provider,omitempty"`
	Harness              string  `json:"harness,omitempty"`
	Model                string  `json:"model"`
	Available            bool    `json:"available"`
	AutoRoutable         bool    `json:"auto_routable"`
	Power                int     `json:"power,omitempty"`
	InputCostPerMTokUSD  float64 `json:"input_cost_per_mtok_usd,omitempty"`
	OutputCostPerMTokUSD float64 `json:"output_cost_per_mtok_usd,omitempty"`
	SpeedTokensPerSec    float64 `json:"speed_tokens_per_sec,omitempty"`
	CatalogRef           string  `json:"catalog_ref,omitempty"`
	RankPosition         int     `json:"rank_position,omitempty"`
}

// recentRoutingDecision is a merged view of a single routing decision sourced from
// either the live Fizeau RouteStatus report or a kind:routing bead evidence event.
//
// The live report carries current route decisions and cooldowns. kind:routing bead
// events remain for audit-only provenance.
type recentRoutingDecision struct {
	ObservedAt   time.Time
	Source       string // "bead-evidence" or "route-status"
	BeadID       string // populated for bead-evidence entries
	Harness      string // populated for route-status entries
	Provider     string // route-status decision provider or bead-evidence resolved_provider
	Model        string
	RouteReason  string // populated for bead-evidence entries
	Success      bool   // populated for route-status entries
	SuccessKnown bool   // false for bead-evidence entries (success not recorded)
	LatencyMS    int    // populated for route-status entries
}

// beadRoutingDecisionsFromStore reads kind:routing evidence events from all beads
// in the store at workDir/.ddx and returns them as recentRoutingDecision entries.
func beadRoutingDecisionsFromStore(workDir string) []recentRoutingDecision {
	store := bead.NewStore(filepath.Join(workDir, ".ddx"))
	beads, err := store.ReadAll()
	if err != nil {
		return nil
	}
	var out []recentRoutingDecision
	for _, b := range beads {
		events := routingEventsFromBeadExtra(b.Extra)
		for _, e := range events {
			d := recentRoutingDecision{
				ObservedAt: e.CreatedAt,
				Source:     "bead-evidence",
				BeadID:     b.ID,
			}
			if e.Body != "" {
				var body struct {
					ResolvedProvider string `json:"resolved_provider"`
					ResolvedModel    string `json:"resolved_model"`
					RouteReason      string `json:"route_reason"`
				}
				if jsonErr := json.Unmarshal([]byte(e.Body), &body); jsonErr == nil {
					d.Provider = body.ResolvedProvider
					d.Model = body.ResolvedModel
					d.RouteReason = body.RouteReason
				}
			}
			out = append(out, d)
		}
	}
	return out
}

// recentRoutingDecisionsFromReport converts the live RouteStatus report into
// recentRoutingDecision rows.
func recentRoutingDecisionsFromReport(report *agentlib.RouteStatusReport) []recentRoutingDecision {
	if report == nil {
		return nil
	}
	var out []recentRoutingDecision
	for _, route := range report.Routes {
		if route.LastDecision == nil || route.LastDecisionAt.IsZero() {
			continue
		}
		out = append(out, recentRoutingDecision{
			ObservedAt:   route.LastDecisionAt,
			Source:       "route-status",
			Harness:      route.LastDecision.Harness,
			Provider:     route.LastDecision.Provider,
			Model:        route.LastDecision.Model,
			RouteReason:  route.LastDecision.Reason,
			SuccessKnown: false,
		})
	}
	return out
}

// routingEventsFromBeadExtra extracts kind:routing BeadEvents from a bead's
// Extra map without an additional store read. Extra["events"] is stored as
// []any of map[string]any when loaded from JSONL.
func routingEventsFromBeadExtra(extra map[string]any) []bead.BeadEvent {
	if extra == nil {
		return nil
	}
	raw, ok := extra["events"]
	if !ok {
		return nil
	}
	items, ok := raw.([]any)
	if !ok {
		return nil
	}
	var out []bead.BeadEvent
	for _, item := range items {
		m, ok := item.(map[string]any)
		if !ok {
			continue
		}
		k, _ := m["kind"].(string)
		if k != "routing" {
			continue
		}
		e := bead.BeadEvent{Kind: k}
		if v, ok := m["summary"].(string); ok {
			e.Summary = v
		}
		if v, ok := m["body"].(string); ok {
			e.Body = v
		}
		if v, ok := m["actor"].(string); ok {
			e.Actor = v
		}
		if v, ok := m["source"].(string); ok {
			e.Source = v
		}
		if v, ok := m["created_at"].(string); ok {
			if t, err := time.Parse(time.RFC3339, v); err == nil {
				e.CreatedAt = t
			}
		}
		out = append(out, e)
	}
	return out
}

// routeStatusDecisionJSON is the JSON-serialisable form of one routing decision
// from either the live RouteStatus report ("route-status") or kind:routing bead
// evidence ("bead-evidence").
type routeStatusDecisionJSON struct {
	ObservedAt      string `json:"observed_at"`
	Source          string `json:"source"`                     // "bead-evidence" or "route-status"
	BeadID          string `json:"bead_id,omitempty"`          // bead-evidence only
	Harness         string `json:"harness,omitempty"`          // route-status only
	CanonicalTarget string `json:"canonical_target,omitempty"` // route-status only
	Provider        string `json:"provider,omitempty"`         // bead-evidence only
	Model           string `json:"model,omitempty"`
	RouteReason     string `json:"route_reason,omitempty"` // bead-evidence only
	Success         bool   `json:"success,omitempty"`
	LatencyMs       int    `json:"latency_ms,omitempty"`
}

type routeStatusCooldownJSON struct {
	Provider      string `json:"provider"`
	CooldownUntil string `json:"cooldown_until"`
}

type routeStatusCooldown struct {
	provider      string
	cooldownUntil time.Time
}

func routeStatusProvidersJSON(providers []agentlib.ProviderInfo, harnesses []agentlib.HarnessInfo) []routeStatusProviderJSON {
	harnessByName := make(map[string]agentlib.HarnessInfo, len(harnesses))
	for _, h := range harnesses {
		harnessByName[h.Name] = h
	}

	rows := make([]routeStatusProviderJSON, 0, len(providers)+len(harnesses))
	seen := make(map[string]struct{}, len(providers))
	for _, p := range providers {
		seen[p.Name] = struct{}{}
		row := routeStatusProviderJSON{
			Name:         p.Name,
			Type:         p.Type,
			Status:       p.Status,
			DefaultModel: p.DefaultModel,
			Quota:        formatQuotaState(p.Quota),
			Usage:        formatUsageWindows(p.UsageWindows),
		}
		if p.CooldownState != nil && !p.CooldownState.Until.IsZero() {
			row.CooldownUntil = p.CooldownState.Until.UTC().Format(time.RFC3339)
		}
		if p.LastError != nil {
			row.Error = p.LastError.Detail
		}
		if h, ok := harnessByName[p.Name]; ok {
			row.CostClass = h.CostClass
			if row.Quota == "" {
				row.Quota = formatQuotaState(h.Quota)

package server

// Provider availability and utilization endpoints — FEAT-002 §26-27.
// Field semantics, unknown-state rules, and the zero-fabrication contract are
// governed by FEAT-014 (dashboard read model).

import (
	"context"
	"encoding/json"
	"net/http"
	"sort"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	agentlib "github.com/DocumentDrivenDX/fizeau"
)

// ---- Read-model types ----

// ProviderSummary is the list-response item for GET /api/providers.
// -1 sentinels on numeric fields mean unknown (FEAT-014 zero-fabrication).
type ProviderSummary struct {
	Harness            string   `json:"harness"`
	DisplayName        string   `json:"display_name"`
	Status             string   `json:"status"`         // available | unavailable | unknown
	AuthState          string   `json:"auth_state"`     // authenticated | unauthenticated | unknown
	QuotaHeadroom      string   `json:"quota_headroom"` // ok | blocked | unknown
	SignalSources      []string `json:"signal_sources"`
	FreshnessTS        string   `json:"freshness_ts,omitempty"`
	LastCheckedTS      string   `json:"last_checked_ts,omitempty"`
	RecentSuccessRate  float64  `json:"recent_success_rate"`   // -1 when sample_count < 3
	RecentLatencyP50MS int      `json:"recent_latency_p50_ms"` // -1 when unknown
	CostClass          string   `json:"cost_class"`
}

// ProviderModelQuota is per-model quota info within a provider detail.
type ProviderModelQuota struct {
	Model         string `json:"model"`
	QuotaHeadroom string `json:"quota_headroom"` // ok | blocked | unknown
	Source        string `json:"source"`
	SourceNote    string `json:"source_note,omitempty"`
}

// ProviderUsageWindow holds token/cost totals for one time window.
// -1 sentinel means unknown per FEAT-014 zero-fabrication contract.
type ProviderUsageWindow struct {
	InputTokens  int     `json:"input_tokens"`
	OutputTokens int     `json:"output_tokens"`
	TotalTokens  int     `json:"total_tokens"`
	CostUSD      float64 `json:"cost_usd"`
	CostNote     string  `json:"cost_note,omitempty"`
}

// ProviderHistoricalUsage holds 7d and 30d usage windows.
type ProviderHistoricalUsage struct {
	Window7D  *ProviderUsageWindow `json:"window_7d,omitempty"`
	Window30D *ProviderUsageWindow `json:"window_30d,omitempty"`
}

// ProviderBurnEstimate is the DDx-derived subscription-pressure estimate.
type ProviderBurnEstimate struct {
	DailyTokenRate   float64 `json:"daily_token_rate"`  // -1 when unknown
	SubscriptionBurn string  `json:"subscription_burn"` // low | moderate | high | unknown
	Source           string  `json:"source,omitempty"`
	Confidence       string  `json:"confidence"` // high | medium | low
	FreshnessTS      string  `json:"freshness_ts,omitempty"`
}

// ProviderPerformance holds DDx-observed latency/success metrics.
type ProviderPerformance struct {
	P50LatencyMS int     `json:"p50_latency_ms"` // -1 when unknown
	P95LatencyMS int     `json:"p95_latency_ms"` // -1 when unknown
	SuccessRate  float64 `json:"success_rate"`   // -1 when sample_count < 3
	SampleCount  int     `json:"sample_count"`
	Window       string  `json:"window"` // "7d"
}

// ProviderRoutingSignals is the routing signal summary within a provider detail.
type ProviderRoutingSignals struct {
	Availability string              `json:"availability"` // available | unavailable | unknown
	RequestFit   string              `json:"request_fit"`  // capable | unknown
	CostEstimate string              `json:"cost_estimate"`
	Performance  ProviderPerformance `json:"performance"`
}

// ProviderDetail is the response shape for GET /api/providers/{harness}.
type ProviderDetail struct {
	Harness         string                   `json:"harness"`
	DisplayName     string                   `json:"display_name"`
	Status          string                   `json:"status"`
	AuthState       string                   `json:"auth_state"`
	Models          []ProviderModelQuota     `json:"models"`
	HistoricalUsage *ProviderHistoricalUsage `json:"historical_usage,omitempty"`
	BurnEstimate    *ProviderBurnEstimate    `json:"burn_estimate,omitempty"`
	RoutingSignals  ProviderRoutingSignals   `json:"routing_signals"`
	SignalSources   []string                 `json:"signal_sources"`
	FreshnessTS     string                   `json:"freshness_ts,omitempty"`
}

// ---- HTTP handlers ----

// handleListProviders serves GET /api/providers — list all configured harnesses
// with routing availability, auth state, quota/headroom, and signal freshness.
// Not project-scoped; provider config is host+user global.
func (s *Server) handleListProviders(w http.ResponseWriter, r *http.Request) {
	now := time.Now().UTC()
	infos, err := listHarnessInfos(r.Context(), s.WorkingDir)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	report := liveRouteStatusReport(r.Context(), s.WorkingDir)

	result := make([]ProviderSummary, 0, len(infos))
	for _, info := range infos {
		result = append(result, buildProviderSummary(info, report, now))
	}
	writeJSON(w, http.StatusOK, result)
}

// handleShowProvider serves GET /api/providers/{harness} — full routing signal
// snapshot per FEAT-014 read-model fields.
func (s *Server) handleShowProvider(w http.ResponseWriter, r *http.Request) {
	harnessName := r.PathValue("harness")
	if harnessName == "" {
		writeJSON(w, http.StatusBadRequest, map[string]string{"error": "harness required"})
		return
	}
	infos, err := listHarnessInfos(r.Context(), s.WorkingDir)
	if err != nil {
		writeJSON(w, http.StatusInternalServerError, map[string]string{"error": err.Error()})
		return
	}
	info, ok := findHarnessInfo(infos, harnessName)
	if !ok {
		writeJSON(w, http.StatusNotFound, map[string]string{"error": "harness not found"})
		return
	}

	now := time.Now().UTC()
	report := liveRouteStatusReport(r.Context(), s.WorkingDir)

	detail := buildProviderDetail(info, report, now)
	writeJSON(w, http.StatusOK, detail)
}

// ---- MCP tool implementations ----

func (s *Server) mcpProviderList() mcpToolResult {
	now := time.Now().UTC()
	infos, err := listHarnessInfos(context.Background(), s.WorkingDir)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText(err.Error())}, IsError: true}
	}

	report := liveRouteStatusReport(context.Background(), s.WorkingDir)

	result := make([]ProviderSummary, 0, len(infos))
	for _, info := range infos {
		result = append(result, buildProviderSummary(info, report, now))
	}
	data, err := json.Marshal(result)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText("[]")}}
	}
	return mcpToolResult{Content: []mcpContent{mcpText(string(data))}}
}

func (s *Server) mcpProviderShow(harnessName string) mcpToolResult {
	if harnessName == "" {
		return mcpToolResult{Content: []mcpContent{mcpText("harness required")}, IsError: true}
	}
	infos, err := listHarnessInfos(context.Background(), s.WorkingDir)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText(err.Error())}, IsError: true}
	}
	info, ok := findHarnessInfo(infos, harnessName)
	if !ok {
		return mcpToolResult{Content: []mcpContent{mcpText("harness not found: " + harnessName)}, IsError: true}
	}

	now := time.Now().UTC()
	report := liveRouteStatusReport(context.Background(), s.WorkingDir)

	detail := buildProviderDetail(info, report, now)
	data, err := json.Marshal(detail)
	if err != nil {
		return mcpToolResult{Content: []mcpContent{mcpText("{}")}}
	}
	return mcpToolResult{Content: []mcpContent{mcpText(string(data))}}
}

// ---- Build helpers ----

func buildProviderSummary(
	info agentlib.HarnessInfo,
	report *agentlib.RouteStatusReport,
	now time.Time,
) ProviderSummary {
	perf := providerPerformanceFromRouteStatus(report, info.Name)
	sources := collectHarnessSignalSources(info)

	var freshnessTS string
	if ts := providerFreshnessTS(info); !ts.IsZero() {
		freshnessTS = ts.UTC().Format(time.RFC3339)
	}

	return ProviderSummary{
		Harness:            info.Name,
		DisplayName:        harnessDisplayName(info.Name),
		Status:             providerStatusStrInfo(info),
		AuthState:          harnessAuthStateStr(info),
		QuotaHeadroom:      harnessQuotaHeadroomStr(info),
		SignalSources:      sources,
		FreshnessTS:        freshnessTS,
		LastCheckedTS:      now.UTC().Format(time.RFC3339),
		RecentSuccessRate:  perf.SuccessRate,
		RecentLatencyP50MS: perf.P50LatencyMS,
		CostClass:          info.CostClass,
	}
}

func buildProviderDetail(
	info agentlib.HarnessInfo,
	report *agentlib.RouteStatusReport,
	now time.Time,
) ProviderDetail {
	perf := providerPerformanceFromRouteStatus(report, info.Name)
	sources := collectHarnessSignalSources(info)

	var freshnessTS string
	if ts := providerFreshnessTS(info); !ts.IsZero() {
		freshnessTS = ts.UTC().Format(time.RFC3339)
	}

	models := buildModelQuotaList(info)
	historicalUsage := computeProviderHistoricalUsage(info)
	burnEstimate := computeProviderBurnEstimate(info, historicalUsage)

	statusStr := providerStatusStrInfo(info)
	return ProviderDetail{
		Harness:         info.Name,
		DisplayName:     harnessDisplayName(info.Name),
		Status:          statusStr,
		AuthState:       harnessAuthStateStr(info),
		Models:          models,
		HistoricalUsage: historicalUsage,
		BurnEstimate:    burnEstimate,
		RoutingSignals: ProviderRoutingSignals{
			Availability: statusStr,
			RequestFit:   harnessRequestFitStr(info),
			CostEstimate: "unknown",
			Performance:  perf,
		},
		SignalSources: sources,
		FreshnessTS:   freshnessTS,
	}
}

