func aggregateUsageFromSessionIndex(logDir, harnessFilter string, since time.Time, mirrored map[string]struct{}) ([]usageRow, error) {
	records, err := readUsageSessionIndexRecords(logDir, harnessFilter, since)
	if err != nil {
		return nil, err
	}
	byHarness := map[string]*usageAgg{}
	order := []string{}
	for _, record := range records {
		if mirrored != nil && record.key != "" {
			if _, ok := mirrored[record.key]; ok {
				continue
			}
		}
		a, exists := byHarness[record.entry.Harness]
		if !exists {
			a = &usageAgg{}
			byHarness[record.entry.Harness] = a
			order = append(order, record.entry.Harness)
		}
		a.addSession(record.entry)
	}
	rows := make([]usageRow, 0, len(order))
	for _, h := range order {
		rows = append(rows, byHarness[h].toRow(h))
	}
	return rows, nil
}

// enrichUsageRowsWithRoutingSignals annotates usage rows with per-harness
// routing signals from the upstream agent service. When the service is
// unavailable the rows are returned unchanged.
func enrichUsageRowsWithRoutingSignals(workDir string, rows []usageRow) []usageRow {
	svc, err := agent.NewServiceFromWorkDir(workDir)

	// Check for local modifications
	modifications, err := getLocalModificationsFromDir(workingDir)
	if err != nil {
		return nil, err
	}
	status.Modifications = modifications

	// Check upstream updates if requested
	if checkUpstream {
		upstream, err := checkUpstreamUpdatesFromDir(workingDir)
		if err != nil {
			return nil, err
		}
		status.UpstreamInfo = upstream
	}

	// Collect resource information
	resources, err := getStatusResourcesFromDir(workingDir)
	if err != nil {
		return nil, err
	}
	status.Resources = resources
	status.Usage = collectStatusUsage(workingDir)

	status.Performance.CollectionTime = time.Since(start)
	return status, nil
}

func collectStatusUsage(workingDir string) []usageRow {
	since, err := parseSince("30d")
	if err != nil {
		return nil
	}

	logDir := agent.SessionLogDirForWorkDir(workingDir)
	rows, err := aggregateUsageFromRoutingMetrics(logDir, "", since)
	if err != nil {
		return nil
	}
	if len(rows) == 0 {
		rows, err = aggregateUsageFromSessionIndex(logDir, "", since, nil)
	}
	if err != nil || len(rows) == 0 {
		return nil
	}

	return enrichUsageRowsWithRoutingSignals(workingDir, rows)
}

func getVersionInfoFromDir(workingDir string) (version, hash string, err error) {
	// Try to get from .ddx.yml first
	configPath := ".ddx.yml"
	if workingDir != "" {
		configPath = filepath.Join(workingDir, ".ddx.yml")
	}

	// Create a temporary viper instance for this specific config
	v := viper.New()
	v.SetConfigFile(configPath)
	if err := v.ReadInConfig(); err == nil {
		version = v.GetString("version")
	}

	if version == "" {
		version = "v0.0.1" // Default if not set
	}

	// Get git commit hash from .ddx directory
	ddxDir := ".ddx"
	if workingDir != "" {
		ddxDir = filepath.Join(workingDir, ".ddx")
	}

	if _, err := os.Stat(ddxDir); os.IsNotExist(err) {
		return version, "unknown", nil
	}

	cmd := gitpkg.Command(context.Background(), ddxDir, "rev-parse", "--short", "HEAD")
	output, err := cmd.Output()
	if err != nil {
